export enum Platform {
  YOUTUBE = 'YouTube',
  INSTAGRAM = 'Instagram',
  TIKTOK = 'TikTok',
  LINKEDIN = 'LinkedIn',
  TWITTER = 'Twitter/X'
}

export interface GeneratedContent {
  title: string;
  description: string;
  tags: string[];
  strategy: string;
  sources?: Array<{ title: string; uri: string }>;
