import { GoogleGenAI } from "@google/genai";
import { GeneratedContent, Platform } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateSeoContent = async (
  topic: string,
  platform: Platform
): Promise<GeneratedContent> => {
  const prompt = `
    Act as a world-class Social Media SEO Expert and Strategist. 
    I need you to generate optimized content for the platform: "${platform}" regarding the topic: "${topic}".

    You MUST use Google Search to research the very latest algorithm trends, trending keywords, and viral hooks specific to this topic and platform right now.

    Return the response as a valid JSON object wrapped in a code block \`\`\`json ... \`\`\`. 

    The JSON object must have the following structure:
    {
      "title": "A highly engaging, click-worthy title or caption hook.",
      "description": "A complete, SEO-rich description or caption. Include line breaks as \\n characters.",
      "tags": ["tag1", "tag2", "tag3"],
      "strategy": "A brief explanation of why this content is optimized based on current trends."
    }

    Specific Instructions per Platform:
    - YouTube: Title should be under 100 chars, high CTR. Description should be detailed with keywords. Tags should be comma-separated style keywords.
    - Instagram: Title is the "Hook" (first line). Description is the caption. Tags are Hashtags (start with #).
    - TikTok: Title is the on-screen hook. Description is the caption. Tags are Hashtags.
    - LinkedIn: Professional tone, engage with industry trends.
    - Twitter/X: Short, punchy, thread-starter style if applicable.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        // We do not use responseSchema with googleSearch as it can conflict in strict modes or hide grounding metadata
      },
    });

    const text = response.text || "";

    // Extract sources if available
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    const sources = groundingChunks
      ?.map((chunk: any) => chunk.web ? { title: chunk.web.title, uri: chunk.web.uri } : null)
      .filter((s: any) => s !== null) || [];

    // Parse JSON from code block
    const jsonMatch = text.match(/```json\n([\s\S]*?)\n```/) || text.match(/```([\s\S]*?)```/);

    if (jsonMatch && jsonMatch[1]) {
      try {
        const parsed = JSON.parse(jsonMatch[1]);
        return {
          ...parsed,
          sources
        };
      } catch (e) {
        console.error("Failed to parse JSON from code block", e);
        throw new Error("Failed to parse generated content.");
      }
    } else {
        // Fallback: try to parse the raw text if it looks like JSON
        try {
            const start = text.indexOf('{');
            const end = text.lastIndexOf('}');
            if (start !== -1 && end !== -1) {
                const jsonStr = text.substring(start, end + 1);
                const parsed = JSON.parse(jsonStr);
                return { ...parsed, sources };
            }
        } catch(e) {
             console.error("Fallback JSON parse failed", e);
        }

      throw new Error("The model did not return a valid JSON format. Please try again.");
    }

  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

