      generateForPlatform(topic, Platform.YOUTUBE),
      generateForPlatform(topic, Platform.INSTAGRAM)
    ]);

    return { youtube, instagram };
  } catch (error) {
    console.error("Dual generation error", error);
    throw error;
  }
};

