import { GoogleGenAI } from "@google/genai";
import { GeneratedContent, Platform, DualPlatformContent } from "../types";

const generateForPlatform = async (
  topic: string,
  platform: Platform,
  apiKey: string
): Promise<GeneratedContent> => {
  // Initialize AI with the user's specific key for this request
  const ai = new GoogleGenAI({ apiKey });

  const prompt = `
    Act as a world-class Social Media SEO Expert and Strategist. 
    I need you to generate optimized content for the platform: "${platform}" regarding the topic: "${topic}".

    You MUST use Google Search to research the very latest algorithm trends, trending keywords, and viral hooks specific to this topic and platform right now.

    Return the response as a valid JSON object wrapped in a code block \`\`\`json ... \`\`\`. 

    The JSON object must have the following structure:
    {
      "title": "A highly engaging, click-worthy title or caption hook.",
      "description": "A complete, SEO-rich description or caption. Include line breaks as \\n characters.",
      "tags": ["tag1", "tag2", "tag3"],
      "strategy": "A brief explanation of why this content is optimized based on current trends."
    }

    Specific Instructions per Platform:
    - YouTube: Title should be under 100 chars, high CTR. Description should be detailed with keywords. Tags should be comma-separated style keywords.
    - Instagram: Title is the "Hook" (first line). Description is the caption. Tags are Hashtags (start with #).
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
      },
    });

    const text = response.text || "";

    // Extract sources if available
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    const sources = groundingChunks
      ?.map((chunk: any) => chunk.web ? { title: chunk.web.title, uri: chunk.web.uri } : null)
      .filter((s: any) => s !== null) || [];

    // Parse JSON from code block
    const jsonMatch = text.match(/```json\n([\s\S]*?)\n```/) || text.match(/```([\s\S]*?)```/);

    if (jsonMatch && jsonMatch[1]) {
      try {
        const parsed = JSON.parse(jsonMatch[1]);
        return {
          ...parsed,
          sources
        };
      } catch (e) {
        console.error("Failed to parse JSON from code block", e);
        throw new Error(`Failed to parse ${platform} content.`);
      }
    } else {
        // Fallback: try to parse the raw text if it looks like JSON
        try {
            const start = text.indexOf('{');
            const end = text.lastIndexOf('}');
            if (start !== -1 && end !== -1) {
                const jsonStr = text.substring(start, end + 1);
                const parsed = JSON.parse(jsonStr);
                return { ...parsed, sources };
            }
        } catch(e) {
             console.error("Fallback JSON parse failed", e);
        }

      throw new Error(`The model did not return a valid JSON format for ${platform}. Please try again.`);
    }

  } catch (error) {
    console.error(`Gemini API Error (${platform}):`, error);
    throw error;
  }
};

export const generateDualSeoContent = async (topic: string, apiKey: string): Promise<DualPlatformContent> => {
  try {
    const [youtube, instagram] = await Promise.all([
      generateForPlatform(topic, Platform.YOUTUBE, apiKey),
      generateForPlatform(topic, Platform.INSTAGRAM, apiKey)
    ]);

    return { youtube, instagram };
  } catch (error) {
    console.error("Dual generation error", error);
    throw error;
  }
};

import React, { useState, useEffect } from 'react';
import { Platform, DualPlatformContent } from './types';
import { generateDualSeoContent } from './services/geminiService';
import ResultDisplay from './components/ResultDisplay';
import { Sparkles, Search, Loader2, Youtube, Instagram, Key, LogOut, ArrowRight, ShieldCheck } from 'lucide-react';

const App: React.FC = () => {
  const [apiKey, setApiKey] = useState<string | null>(null);
  const [tempKey, setTempKey] = useState('');

  const [topic, setTopic] = useState('');
  const [result, setResult] = useState<DualPlatformContent | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Load key from storage on mount
  useEffect(() => {
    const storedKey = localStorage.getItem('seoom_api_key');
    if (storedKey) {
      setApiKey(storedKey);
    }
  }, []);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (tempKey.trim().length > 10) {
      localStorage.setItem('seoom_api_key', tempKey.trim());
      setApiKey(tempKey.trim());
      setTempKey('');
    }
  };

  const handleLogout = () => {
    localStorage.removeItem('seoom_api_key');
    setApiKey(null);
    setResult(null);
    setTopic('');
  };

  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!topic.trim() || !apiKey) return;

    setLoading(true);
    setError(null);
    setResult(null);

    try {
      const data = await generateDualSeoContent(topic, apiKey);
      setResult(data);
    } catch (err: any) {
      setError(err.message || 'Something went wrong. Please check your API key and try again.');
    } finally {
      setLoading(false);
    }
  };

  if (!apiKey) {
    return (
      <div className="min-h-screen bg-[#0f172a] text-slate-200 selection:bg-indigo-500/30 flex items-center justify-center p-6">
        <div className="fixed inset-0 z-0 overflow-hidden pointer-events-none">
            <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-indigo-600/10 rounded-full blur-[100px]" />
            <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-pink-600/10 rounded-full blur-[100px]" />
        </div>

        <div className="relative z-10 w-full max-w-md bg-slate-900/80 backdrop-blur-xl border border-slate-700/50 rounded-3xl p-8 shadow-2xl animate-in fade-in slide-in-from-bottom-4">
            <div className="text-center mb-8">
                <div className="inline-flex justify-center items-center w-16 h-16 bg-gradient-to-br from-indigo-500/20 to-purple-500/20 rounded-2xl mb-4 border border-indigo-500/30">
                    <Key className="w-8 h-8 text-indigo-400" />
                </div>
                <h1 className="text-3xl font-bold text-white mb-2">Welcome to <span className="text-transparent bg-clip-text bg-gradient-to-r from-indigo-400 to-purple-400">SEOOM</span> AI</h1>
                <p className="text-slate-400">Enter your Google Gemini API Key to start generating viral content.</p>
            </div>

            <form onSubmit={handleLogin} className="space-y-6">
                <div className="space-y-2">
                    <label htmlFor="apiKey" className="text-sm font-medium text-slate-300 ml-1">API Key</label>
                    <input
                        id="apiKey"
                        type="password"
                        value={tempKey}
                        onChange={(e) => setTempKey(e.target.value)}
                        placeholder="AIzaSy..."
                        className="w-full bg-slate-950/50 border border-slate-700 text-white rounded-xl px-4 py-3 focus:ring-2 focus:ring-indigo-500/50 focus:border-indigo-500 outline-none transition-all placeholder-slate-600"
                        required
                    />
                </div>

                <button
                    type="submit"
                    disabled={tempKey.length < 10}
                    className="w-full bg-indigo-600 hover:bg-indigo-500 text-white font-semibold py-3 rounded-xl transition-all disabled:opacity-50 disabled:hover:bg-indigo-600 flex items-center justify-center gap-2 group"
                >
                    <span>Get Started</span>
                    <ArrowRight className="w-4 h-4 group-hover:translate-x-1 transition-transform" />
                </button>
            </form>

            <div className="mt-8 pt-6 border-t border-slate-800 text-center">
                <p className="text-xs text-slate-500 mb-2">Don't have a key?</p>
                <a 
                    href="https://aistudio.google.com/app/apikey" 
                    target="_blank" 
                    rel="noopener noreferrer"
                    className="text-sm text-indigo-400 hover:text-indigo-300 font-medium inline-flex items-center gap-1 hover:underline"
                >
                    Get a free Gemini API Key <ShieldCheck className="w-3 h-3" />
                </a>
                <p className="text-[10px] text-slate-600 mt-4">
                    Your key is stored locally on your device and never sent to our servers.
                </p>
            </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#0f172a] text-slate-200 selection:bg-indigo-500/30 flex flex-col">
      {/* Background Decor */}
      <div className="fixed inset-0 z-0 overflow-hidden pointer-events-none">
        <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-indigo-600/10 rounded-full blur-[100px]" />
        <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-pink-600/10 rounded-full blur-[100px]" />
      </div>

      <div className="relative z-10 max-w-7xl mx-auto px-6 py-12 md:py-20 flex-grow w-full">

        {/* Header */}
        <div className="flex flex-col md:flex-row justify-between items-center mb-12 relative">
            <div className="text-center md:text-left w-full">
                <div className="flex flex-col md:flex-row items-center justify-between gap-4">
                     <div className="space-y-2 text-center md:text-left">
                        <div className="inline-flex items-center gap-2 px-3 py-1 rounded-full bg-slate-800/50 border border-slate-700 text-indigo-400 text-xs font-medium">
                            <Sparkles className="w-3 h-3" />
                            <span>Powered by Gemini 3 Flash & Live Search</span>
                        </div>
                        <h1 className="text-4xl font-bold text-white tracking-tight">
                            <span className="text-transparent bg-clip-text bg-gradient-to-r from-indigo-400 to-purple-400">SEOOM</span> AI
                        </h1>
                     </div>

                     <button 
                        onClick={handleLogout}
                        className="flex items-center gap-2 px-4 py-2 text-sm text-slate-400 hover:text-white hover:bg-slate-800/50 rounded-lg transition-colors border border-transparent hover:border-slate-700"
                     >
                        <LogOut className="w-4 h-4" />
                        <span>Change API Key</span>
                     </button>
                </div>
            </div>
        </div>

        <div className="text-center mb-12">
             <p className="text-lg text-slate-400 max-w-2xl mx-auto">
                Generate viral, SEO-optimized content for 
                <span className="text-red-400 font-medium"> YouTube</span> & 
                <span className="text-pink-400 font-medium"> Instagram</span> simultaneously.
            </p>
        </div>

        {/* Controls */}
        <div className="max-w-3xl mx-auto mb-12">

            {/* Platform Badges */}
            <div className="flex justify-center gap-4 mb-6">
                <div className="flex items-center gap-2 px-4 py-2 bg-red-950/30 border border-red-900/50 rounded-full text-red-200 text-sm">
                    <Youtube className="w-4 h-4" />
                    <span>YouTube</span>
                </div>
                <div className="flex items-center gap-2 px-4 py-2 bg-pink-950/30 border border-pink-900/50 rounded-full text-pink-200 text-sm">
                    <Instagram className="w-4 h-4" />
                    <span>Instagram</span>
                </div>
            </div>

            <form onSubmit={handleGenerate} className="relative group">
                <div className="absolute inset-0 bg-gradient-to-r from-indigo-500 to-pink-500 rounded-2xl opacity-20 group-hover:opacity-30 transition-opacity blur-md" />
                <div className="relative flex items-center bg-slate-900 border border-slate-700 rounded-2xl p-2 shadow-2xl transition-all focus-within:border-indigo-500/50 focus-within:ring-4 focus-within:ring-indigo-500/20">
                    <Search className="w-6 h-6 text-slate-500 ml-4" />
                    <input
                        type="text"
                        value={topic}
                        onChange={(e) => setTopic(e.target.value)}
                        placeholder="What's your content about? (e.g., 'Travel Vlog Japan')"
                        className="w-full bg-transparent border-none text-lg text-white placeholder-slate-500 focus:ring-0 px-4 py-4"
                        disabled={loading}
                    />
                    <button
                        type="submit"
                        disabled={loading || !topic.trim()}
                        className="bg-indigo-600 hover:bg-indigo-500 text-white px-8 py-3 rounded-xl font-semibold transition-all disabled:opacity-50 disabled:hover:bg-indigo-600 flex items-center gap-2"
                    >
                        {loading ? (
                            <>
                                <Loader2 className="w-5 h-5 animate-spin" />
                                <span>Thinking...</span>
                            </>
                        ) : (
                            <>
                                <span>Generate</span>
                                <Sparkles className="w-4 h-4" />
                            </>
                        )}
                    </button>
                </div>
            </form>

            {/* Suggestions / Hints */}
            <div className="mt-4 flex flex-wrap justify-center gap-2 text-sm text-slate-500">
                <span>Try:</span>
                <button onClick={() => setTopic("Travel vlog Japan 2025")} className="hover:text-indigo-400 transition-colors">"Japan Travel Vlog"</button>
                <span>•</span>
                <button onClick={() => setTopic("Digital Marketing Tips for Beginners")} className="hover:text-indigo-400 transition-colors">"Digital Marketing"</button>
                <span>•</span>
                <button onClick={() => setTopic("Healthy Meal Prep 101")} className="hover:text-indigo-400 transition-colors">"Healthy Meal Prep"</button>
            </div>
        </div>

        {/* Error Message */}
        {error && (
            <div className="max-w-2xl mx-auto bg-red-900/20 border border-red-800/50 text-red-200 p-4 rounded-xl mb-8 text-center animate-in fade-in">
                {error}
            </div>
        )}

        {/* Results */}
        {result && (
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 mb-20">
                <ResultDisplay content={result.youtube} platform={Platform.YOUTUBE} />
                <ResultDisplay content={result.instagram} platform={Platform.INSTAGRAM} />
            </div>
        )}

      </div>

      {/* Footer */}
      <div className="relative z-10 py-6 text-center border-t border-slate-800/50">
        <p className="text-slate-500 text-sm">
          Created by{' '}
          <a 
            href="http://instagram.com/keshavah_reddy" 
            target="_blank" 
            rel="noopener noreferrer"
            className="text-indigo-400 hover:text-indigo-300 font-medium transition-colors"
          >
            @KESHAVAH_REDDY
          </a>
        </p>
      </div>
    </div>
  );
};

export default App;
